function tableSlider(tableType, tableName) {
  const currentTable = document.querySelectorAll(`${tableType} ${tableName}`)[0];
  const mc = new Hammer.Manager(currentTable);
  let currentInfo = 0;
  const ligaElements = $(`${tableType} ${tableName} .liga-table__item-elemet`);
  const ligaElementsNumber = $(`${tableType} ${tableName} .liga-table__item-elemet`).length -1;
  const ligaContent = $(`${tableType} ${tableName} .liga-table__content`);

  mc.add(new Hammer.Swipe( {direction: Hammer.DIRECTION_HORIZONTAL, threshold: 10, velocity: 0.1} ));

  mc.on("swipeleft", swipeLeft);
  mc.on("swiperight", swipeRight);


  function swipeLeft() {
    if (currentInfo < ligaElementsNumber) {
      $(ligaElements).removeClass('liga-table__item_active');

      ligaContent.each(function() {
        $(this).children().eq(currentInfo).removeClass('liga-table__item_active');
      });

      currentInfo++;
      $(ligaElements[currentInfo]).addClass('liga-table__item_active');

      ligaContent.each(function() {
        $(this).children().eq(currentInfo).addClass('liga-table__item_active');
      });
    }
  }

  function swipeRight() {
    if (currentInfo > 0) {
      $(ligaElements).removeClass('liga-table__item_active');

      ligaContent.each(function() {
        $(this).children().eq(currentInfo).removeClass('liga-table__item_active');
      });

      currentInfo--;

      $(ligaElements[currentInfo]).addClass('liga-table__item_active');

      ligaContent.each(function() {
        $(this).children().eq(currentInfo).addClass('liga-table__item_active');
      });
    }
  }
}

function tableSwitcher(prevButton, nextButton, switchers, currentPosition) {
  const switchersNumber = switchers.length -1;

  nextButton.click(function () {
    if(switchersNumber > currentPosition) {
      switchers.removeClass('liga-table-switch__item_active');
      currentPosition++;
      $(switchers[currentPosition]).addClass('liga-table-switch__item_active');
      $(switchers[currentPosition]).click();
    }
  });

  prevButton.click(function () {
    if(currentPosition > 0) {
      switchers.removeClass('liga-table-switch__item_active');
      currentPosition--;
      $(switchers[currentPosition]).addClass('liga-table-switch__item_active');
      $(switchers[currentPosition]).click();
    }
  });
}

function isActive(className, activeClass, blurCounter) {
  if(!$(className).hasClass(activeClass)) {
    blurCounter--;
    setBlur(blurCounter);
  } else {
    blurCounter++;
    setBlur(blurCounter);
  }
}

function setBlur (blurCounter) {
  if (blurCounter > 0) {
    $('.header').addClass('blur');
    $('.liga-info').addClass('blur');
    $('.board').addClass('blur');
    $('.partners-section').addClass('blur');
    $('.teams-header').addClass('blur');
    $('.team-content').addClass('blur');
    $('.team-content__line').addClass('blur');
    $('body').addClass('open-modal');
  } else {
    $('.header').removeClass('blur');
    $('.liga-info').removeClass('blur');
    $('.board').removeClass('blur');
    $('.partners-section').removeClass('blur');
    $('.teams-header').removeClass('blur');
    $('.team-content').removeClass('blur');
    $('.team-content__line').removeClass('blur');
    $('body').removeClass('open-modal');
  }
};

function showPlayerField(triggerButton, fieldWrapper, field) {
  let playerCounter = 0;
  const fields = $(`${fieldWrapper} ${field}`);

  $(triggerButton).click(function() {
    if (playerCounter < 20) {
      $(fields[playerCounter]).addClass('visible');
      playerCounter++;
    } else {
      $(triggerButton).addClass('hide')
    }
  });
}